CREATE OR REPLACE FUNCTION public.sync_bezahlt_from_events() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $fn$ DECLARE _aid uuid; _paid boolean; BEGIN _aid := COALESCE(NEW.auftrag_id, OLD.auftrag_id); SELECT EXISTS (SELECT 1 FROM public.auftrag_zahlungsereignisse WHERE auftrag_id = _aid AND storniert = false AND payment_type = 'erledigt_bezahlt') INTO _paid; UPDATE public.auftraege SET bezahlt = _paid, bezahlt_am = CASE WHEN _paid THEN COALESCE(bezahlt_am, now()) ELSE NULL END WHERE id = _aid AND bezahlt IS DISTINCT FROM _paid; RETURN NULL; END; $fn$; DROP TRIGGER IF EXISTS trg_sync_bezahlt_from_events ON public.auftrag_zahlungsereignisse; CREATE TRIGGER trg_sync_bezahlt_from_events AFTER INSERT OR UPDATE OR DELETE ON public.auftrag_zahlungsereignisse FOR EACH ROW EXECUTE FUNCTION public.sync_bezahlt_from_events(); CREATE OR REPLACE FUNCTION public.protect_auftrag_worker_update() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $fn$ DECLARE _res public.auftraege%ROWTYPE; BEGIN IF public.is_staff(auth.uid()) THEN RETURN NEW; END IF; _res := OLD; _res.status := NEW.status; _res.abschluss_notizen := NEW.abschluss_notizen; _res.abgeschlossen_am := NEW.abgeschlossen_am; _res.updated_at := now(); RETURN _res; END; $fn$; ALTER TABLE public.auftraege DISABLE TRIGGER protect_auftrag_worker_update; UPDATE public.auftraege a SET bezahlt = ev.paid, bezahlt_am = CASE WHEN ev.paid THEN COALESCE(a.bezahlt_am, now()) ELSE NULL END FROM (SELECT x.id, EXISTS (SELECT 1 FROM public.auftrag_zahlungsereignisse e WHERE e.auftrag_id = x.id AND e.storniert = false AND e.payment_type = 'erledigt_bezahlt') AS paid FROM public.auftraege x) ev WHERE ev.id = a.id AND a.bezahlt IS DISTINCT FROM ev.paid; ALTER TABLE public.auftraege ENABLE TRIGGER protect_auftrag_worker_update;